{
  "scope": "Tenant",
  "templateKey": "tenant.custom_invoice_reminder",
  "name": "Recordatorio de factura pendiente",
  "description": "Enviado 3 dias antes del vencimiento de una factura."
}

{
  "subject": "Recordatorio: tu factura {{ invoice_number }} vence pronto",
  "htmlContent": "<p>Hola {{ user_name }}, tu factura {{ invoice_number }} vence el {{ due_date }}.</p>",
  "textContent": "Hola {{ user_name }}, tu factura {{ invoice_number }} vence el {{ due_date }}.",
  "designJson": null,
  "layoutId": "{{scribeLayoutId}}",
  "layoutVersionNumber": 1,
  "variableDefinitions": [
    { "name": "user_name", "type": "String", "required": true, "defaultValue": null, "description": "Nombre del cliente" },
    { "name": "invoice_number", "type": "String", "required": true, "defaultValue": null, "description": "Numero de factura" },
    { "name": "due_date", "type": "Date", "required": true, "defaultValue": null, "description": "Fecha de vencimiento" }
  ]
}

{
  "scope": "Tenant",
  "layoutKey": "tenant-invoice-branding",
  "name": "Layout de facturacion con marca del tenant",
  "description": "Header/footer con el logo y colores del tenant para emails de facturacion."
}
